
"use client"

import { useState, useEffect, useMemo, useRef } from "react";
import dynamic from "next/dynamic";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogTitle, DialogDescription, DialogHeader } from "@/components/ui/dialog";
import {
  Zap, Loader2, Navigation, Timer, Flag, Trophy, MapPin, Clock, Gauge, Radio, StopCircle, ShieldAlert, ChevronRight, Map as MapIcon, RotateCcw
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking } from "@/firebase";
import { doc, collection, query, where, getCountFromServer } from "firebase/firestore";
import { useDriving } from "@/context/driving-context";
import { ManeuverIcon } from "@/components/navigation/maneuver-icon";

const RouteMap = dynamic(() => import("@/components/telemetry/route-map"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-zinc-950 animate-pulse rounded-[2.5rem]" />
});

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const {
    speed, isDriving, peakSpeed, tripTime, tripDistance,
    runMode, dragTime, isDragFinished, isDragActive, countdown, isJumpStart,
    isNavigating, currentStep, currentRoadName, distanceToNextStep, remainingDistance, remainingDuration,
    destination, routePoints, currentCoords, heading,
    startTrip, stopTrip, resetTrip, requestWakeLock, setRunMode
  } = useDriving();

  const [mounted, setMounted] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [cityRank, setCityRank] = useState<number | null>(null);
  const [isRankingLoading, setIsRankingLoading] = useState(false);
  const [liveDragTimer, setLiveDragTimer] = useState(0);
  
  const requestRef = useRef<number>(undefined);
  const startTimeRef = useRef<number>(undefined);

  const { toast } = useToast();

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  // Live timer for drag races with high precision
  useEffect(() => {
    const animate = () => {
      if (startTimeRef.current) {
        setLiveDragTimer((performance.now() - startTimeRef.current) / 1000);
      }
      requestRef.current = requestAnimationFrame(animate);
    };

    if (isDragActive) {
      startTimeRef.current = performance.now();
      requestRef.current = requestAnimationFrame(animate);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      startTimeRef.current = undefined;
      if (!isDragFinished) setLiveDragTimer(0);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isDragActive, isDragFinished]);

  const isWaitingForStart = isDriving && !isDragActive && !isDragFinished && 
    (runMode !== 'free') && !isJumpStart;

  const calculateRanks = async () => {
    if (!db || !profile) return;
    setIsRankingLoading(true);
    try {
      const publicRunsCol = collection(db, "public_runs");
      const runTypeLabel = runMode === 'free' ? 'Top Speed' : runMode;
      const val = (runMode === 'free' || !dragTime) ? peakSpeed : dragTime;

      if (!val || val <= 0) {
        setIsRankingLoading(false);
        return;
      }

      const cityQuery = query(
        publicRunsCol, 
        where("city", "==", profile.city || "Prishtinë"), 
        where("runType", "==", runTypeLabel), 
        runMode === 'free' ? where("peakSpeedKmH", ">", val) : where("dragTime", "<", val)
      );
      const citySnapshot = await getCountFromServer(cityQuery);
      setCityRank(citySnapshot.data().count + 1);
    } catch (e) {
      console.error(e);
    } finally {
      setIsRankingLoading(false);
    }
  };

  useEffect(() => {
    if (isDragFinished && mounted && !showSummary) {
      setShowSummary(true);
      calculateRanks();
      // We don't stop trip immediately to keep the data visible for a moment
    }
  }, [isDragFinished, mounted]);

  const handleStartMission = () => {
    if (runMode !== 'free' && speed > 2) {
      toast({ variant: "destructive", title: "GABIM", description: "Ndalo makinën plotësisht për të filluar testin." });
      return;
    }
    startTrip();
    requestWakeLock();
  };

  const handleStopMission = () => {
    if (isDragFinished || runMode === 'free') {
      setShowSummary(true);
      calculateRanks();
    }
    stopTrip();
  };

  const handleQuickReport = () => {
    if (!db || !currentCoords || !user?.uid) {
      toast({ variant: "destructive", title: "GPS GABIM", description: "Lokacioni nuk është përcaktuar ende." });
      return;
    }
    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type: 'Radar',
      lat: currentCoords.lat,
      lng: currentCoords.lng,
      location: "Raport Live",
      city: profile?.city || "Kosovë",
      createdAt: new Date().toISOString(),
      userId: user?.uid
    });
    toast({ title: "U RAPORTUA!", description: "Radari u shënua në hartë." });
  };

  const handleSaveRun = () => {
    if (!user?.uid || !db || !profile) return;
    setIsSaving(true);
    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Kosovë",
      runType: runMode === 'free' ? 'Top Speed' : runMode,
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      dragTime: dragTime,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      carProfileId: "primary"
    };

    addDocumentNonBlocking(collection(db, "users", user.uid, "runs"), runData);
    addDocumentNonBlocking(collection(db, "public_runs"), runData);

    toast({ title: "REKORD I RI!", description: "Gara u ruajt me sukses në Ranking." });
    setIsSaving(false);
    setShowSummary(false);
    resetTrip();
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-black flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  return (
    <div className="flex flex-col min-h-screen bg-[#050505] text-white pb-24 overflow-x-hidden safe-top relative no-scrollbar selection:bg-red-500/30">
      
      {/* Header Bar */}
      <div className="px-6 pt-6 flex items-center justify-between z-50">
        <div className="flex flex-col">
          <h1 className="text-xl font-black italic tracking-tighter leading-none">DRIVERANK <span className="text-red-600">KS</span></h1>
          <span className="text-[8px] font-black uppercase tracking-[0.4em] text-white/30 mt-1.5">Elite Telemetry v2.0</span>
        </div>
        <div className="flex items-center gap-2 bg-white/5 border border-white/10 px-4 py-2 rounded-2xl backdrop-blur-md">
          <Clock className="w-3 h-3 text-accent" />
          <span className="text-[10px] font-black tabular-nums">{new Date().toLocaleTimeString('sq-AL', { hour: '2-digit', minute: '2-digit' })}</span>
        </div>
      </div>

      {/* Mode Selector - Only if not driving */}
      {!isDriving && (
        <div className="px-6 mt-6 flex gap-2 overflow-x-auto no-scrollbar apple-slide-up stagger-1">
          {['free', '0-60', '0-100', '100-200', '1/4mile'].map((mode) => (
            <button
              key={mode}
              onClick={() => setRunMode(mode as any)}
              className={cn(
                "px-5 py-2.5 rounded-2xl font-black text-[9px] uppercase tracking-widest whitespace-nowrap transition-all border-2",
                runMode === mode 
                  ? "bg-red-600 border-red-500 text-white shadow-[0_0_20px_rgba(220,38,38,0.4)] scale-105" 
                  : "bg-white/5 border-white/5 text-white/40 hover:bg-white/10"
              )}
            >
              {mode === 'free' ? 'TOP SPEED' : mode === '1/4mile' ? '1/4 MILE' : mode}
            </button>
          ))}
        </div>
      )}

      {/* Main Display - The Cockpit */}
      <div className="flex-1 flex flex-col items-center justify-center px-4 relative">
        
        {/* Floating Action: Quick Report */}
        <div className="absolute right-6 top-0 z-40 apple-scale-in">
          <Button onClick={handleQuickReport} size="icon" className="w-14 h-14 rounded-[1.5rem] bg-red-600/15 border-2 border-red-600/30 text-red-500 shadow-2xl transition-all active:scale-90 group">
            <Radio className="w-7 h-7 animate-pulse group-active:scale-125 transition-transform" />
          </Button>
        </div>

        {/* Central Instrument Gauge */}
        <div className="relative w-full max-w-[340px] aspect-square flex flex-col items-center justify-center apple-scale-in stagger-2">
          
          {/* Visual Aura Rings */}
          <div className="absolute inset-0 rounded-full border-[12px] border-white/5" />
          <div 
            className={cn(
              "absolute inset-[-12px] rounded-full border-[12px] transition-all duration-300",
              isJumpStart ? "border-red-600/40" : "border-red-600/60 shadow-[0_0_40px_rgba(220,38,38,0.2)]"
            )}
            style={{ 
              clipPath: `inset(0 0 0 0 round 100%)`,
              maskImage: `conic-gradient(black ${Math.min((speed/280)*100, 100)}%, transparent 0)`
            }}
          />

          {/* Mode-Based Central Content */}
          <div className="z-10 flex flex-col items-center w-full h-full justify-center">
            
            {isNavigating ? (
              /* Navigation Focused View */
              <div className="w-full h-full p-10 relative flex flex-col items-center justify-center">
                <div className="absolute inset-0 rounded-full overflow-hidden opacity-30">
                  <RouteMap points={routePoints} userLocation={currentCoords} heading={heading} />
                </div>
                <div className="relative z-20 flex flex-col items-center bg-black/60 backdrop-blur-xl px-8 py-6 rounded-[2.5rem] border border-white/10 shadow-2xl">
                  <span className="text-8xl font-black italic tracking-tighter tabular-nums leading-none">{speed}</span>
                  <span className="text-[10px] font-black uppercase tracking-[0.4em] text-white/40 mt-2">KM/H</span>
                </div>
              </div>
            ) : (
              /* Racing / Drag Focused View */
              <>
                {isJumpStart && (
                  <Badge variant="destructive" className="mb-4 font-black uppercase tracking-widest animate-bounce px-6 py-1.5 text-[10px] rounded-xl shadow-[0_0_20px_rgba(220,38,38,0.5)]">JUMP START!</Badge>
                )}
                
                <span className={cn(
                  "text-[10rem] font-black italic tracking-tighter tabular-nums leading-none transition-all duration-75",
                  isJumpStart ? "text-red-500 scale-95" : "text-white drop-shadow-[0_0_30px_rgba(255,255,255,0.1)]"
                )}>
                  {speed}
                </span>
                
                <div className="flex flex-col items-center -mt-2">
                  <span className="text-xs font-black uppercase tracking-[0.5em] text-white/30">KM / H</span>
                  {isDragActive && (
                    <div className="mt-6 flex flex-col items-center bg-accent/10 px-8 py-3 rounded-[1.8rem] border-2 border-accent/20 backdrop-blur-md apple-scale-in">
                       <span className="text-3xl font-black italic text-accent tabular-nums">
                         {liveDragTimer.toFixed(2)}s
                       </span>
                       <span className="text-[8px] font-black uppercase tracking-widest text-accent/50 mt-1">DRAG TIMER</span>
                    </div>
                  )}
                </div>
              </>
            )}
          </div>

          {/* F1 Countdown Christmas Tree */}
          {isWaitingForStart && (
            <div className="absolute bottom-[-60px] flex items-center gap-4 apple-slide-up bg-zinc-950/80 backdrop-blur-2xl px-8 py-4 rounded-[2rem] border border-white/5 shadow-2xl">
              {[1, 2, 3, 4, 5].map((i) => (
                <div key={i} className={cn(
                  "w-8 h-8 rounded-full border-2 border-white/5 transition-all duration-300 shadow-2xl",
                  countdown >= i ? "bg-red-600 shadow-[0_0_30px_rgba(220,38,38,0.8)] scale-110" : "bg-zinc-900"
                )} />
              ))}
              <div className={cn(
                "w-10 h-10 rounded-full border-2 border-white/10 transition-all duration-500",
                countdown >= 6 ? "bg-green-500 shadow-[0_0_40px_rgba(34,197,94,1)] scale-125" : "bg-zinc-900"
              )} />
            </div>
          )}
        </div>

        {/* Gear Selector Status (P-R-N-D) */}
        <div className="flex gap-6 mt-16 apple-slide-up stagger-3">
           {['P', 'R', 'N', 'D'].map(gear => (
             <span key={gear} className={cn(
               "text-2xl font-black italic transition-all duration-500",
               (speed === 0 && gear === 'P') || (speed > 0 && gear === 'D') 
                 ? "text-red-600 scale-125 drop-shadow-[0_0_15px_rgba(220,38,38,0.6)]" 
                 : "text-white/10"
             )}>
               {gear}
             </span>
           ))}
        </div>

        {/* Navigation Info Bar */}
        {isNavigating && (
          <div className="w-full max-w-[340px] grid grid-cols-3 gap-3 mt-10 apple-slide-up stagger-4">
             <div className="flex flex-col items-center bg-white/5 p-4 rounded-3xl border border-white/5">
                <span className="text-[7px] font-black text-white/40 uppercase tracking-widest mb-1">ARRITJA</span>
                <span className="text-sm font-black italic text-white">
                  {new Date(Date.now() + remainingDuration * 1000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
             </div>
             <div className="flex flex-col items-center bg-accent/5 p-4 rounded-3xl border border-accent/10">
                <span className="text-[7px] font-black text-white/40 uppercase tracking-widest mb-1">KOHA</span>
                <span className="text-sm font-black italic text-accent">{Math.round(remainingDuration / 60)} min</span>
             </div>
             <div className="flex flex-col items-center bg-white/5 p-4 rounded-3xl border border-white/5">
                <span className="text-[7px] font-black text-white/40 uppercase tracking-widest mb-1">DISTANCA</span>
                <span className="text-sm font-black italic text-white">{(remainingDistance / 1000).toFixed(1)} km</span>
             </div>
          </div>
        )}

        {/* Telemetry Grid */}
        <div className="w-full max-w-[340px] grid grid-cols-2 gap-4 mt-8 apple-slide-up stagger-5">
           <Card className="glass border-white/10 p-6 rounded-[2rem] flex flex-col items-center shadow-xl">
              <Timer className="w-5 h-5 text-accent mb-3" />
              <span className="text-[8px] font-black uppercase tracking-widest text-muted-foreground mb-1">TRIP TIMER</span>
              <span className="text-xl font-black italic tabular-nums">{tripTime.toFixed(1)}s</span>
           </Card>
           <Card className="glass border-white/10 p-6 rounded-[2rem] flex flex-col items-center shadow-xl">
              <Flag className="w-5 h-5 text-red-500 mb-3" />
              <span className="text-[8px] font-black uppercase tracking-widest text-muted-foreground mb-1">DISTANCE</span>
              <span className="text-xl font-black italic tabular-nums">{tripDistance.toFixed(1)}m</span>
           </Card>
        </div>

        {/* Primary Action Button */}
        <div className="w-full max-w-[340px] mt-10 apple-slide-up stagger-5">
           <Button
             onClick={isDriving ? handleStopMission : handleStartMission}
             className={cn(
               "w-full h-20 rounded-[2.2rem] font-black text-base uppercase tracking-[0.2em] shadow-2xl transition-all active:scale-95 border-b-[6px] italic",
               isDriving 
                ? "bg-red-950/40 border-red-500/30 text-white" 
                : "bg-red-600 border-red-800 text-white shadow-[0_15px_35px_rgba(220,38,38,0.4)]"
             )}
           >
             {isDriving ? (
               <div className="flex items-center gap-3"><StopCircle className="w-6 h-6" /> STOP MISSION</div>
             ) : (
               <div className="flex items-center gap-3"><Zap className="w-6 h-6 fill-current" /> START {runMode.toUpperCase()}</div>
             )}
           </Button>
           
           {isDriving && (
             <Button 
               variant="ghost" 
               onClick={resetTrip}
               className="w-full mt-4 h-10 rounded-2xl font-black text-[10px] uppercase tracking-widest text-zinc-600 hover:text-white"
             >
               <RotateCcw className="w-3.5 h-3.5 mr-2" /> RESET TELEMETRY
             </Button>
           )}
        </div>
      </div>

      {/* Result Summary Dialog */}
      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="bg-[#0c0c0e] border-white/10 w-[94%] max-w-sm rounded-[3rem] p-10 apple-scale-in">
          <DialogHeader>
            <DialogTitle className="text-3xl font-black italic tracking-tighter text-center uppercase">REZULTATI</DialogTitle>
            <DialogDescription className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest mt-2 text-center">
              {runMode === 'free' ? 'SESSION TOP SPEED' : `${runMode} PERFORMANCE TEST`}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-8 mt-6">
            <div className="bg-zinc-900/50 p-10 rounded-[2.5rem] border border-white/10 text-center relative overflow-hidden">
              <div className="absolute inset-0 bg-red-600/5 blur-3xl" />
              <div className="relative z-10">
                <span className="text-7xl font-black text-white italic tabular-nums leading-none">
                  {(runMode === 'free' || !dragTime) ? peakSpeed : dragTime?.toFixed(2)}
                </span>
                <span className="text-2xl font-black text-red-600 ml-2 italic">
                  {(runMode === 'free' || !dragTime) ? 'km/h' : 's'}
                </span>
              </div>
              
              {isRankingLoading ? (
                <div className="mt-6 flex justify-center"><Loader2 className="w-5 h-5 animate-spin text-accent" /></div>
              ) : (
                <div className="mt-6 flex items-center justify-center gap-2.5 text-[11px] font-black text-accent uppercase tracking-wider">
                  <Trophy className="w-4 h-4" />
                  {cityRank ? `#${cityRank} NË ${profile?.city?.toUpperCase() || 'PRISHTINË'}` : "REKORD I RI I KONFIRMUAR!"}
                </div>
              )}
            </div>

            {/* Run Recap Map */}
            <div className="h-44 w-full rounded-[2rem] overflow-hidden border border-white/10 relative shadow-2xl">
               <RouteMap points={routePoints} />
            </div>

            <div className="flex flex-col gap-3">
              <Button onClick={handleSaveRun} disabled={isSaving} className="w-full h-16 bg-red-600 text-white rounded-[1.8rem] font-black uppercase text-xs tracking-widest shadow-2xl border-b-4 border-red-800 active:scale-95 transition-all">
                {isSaving ? <Loader2 className="w-5 h-5 animate-spin" /> : "RUAJ REKORDIN"}
              </Button>
              <Button variant="ghost" className="w-full h-12 rounded-2xl font-black uppercase text-[10px] text-zinc-600 hover:text-white" onClick={() => { setShowSummary(false); resetTrip(); }}>
                ANULO DHE RESETO
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <BottomNav />
    </div>
  );
}
